import { useEffect, useRef } from "react";

/* ── Inline styles / keyframes injected once ── */
const STYLE = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700&family=DM+Sans:wght@300;400;500;600&display=swap');

  :root {
    --brand: #e03030;
    --brand-dark: #b91c1c;
  }

  .hero-gradient { background: linear-gradient(135deg, #fff7f7 0%, #f0f9ff 50%, #fff5f5 100%); }
  .mesh-bg { position: relative; }

  .btn-primary {
    transition: transform 0.2s, box-shadow 0.2s, background 0.2s;
    box-shadow: 0 4px 20px rgba(224,48,48,0.35);
  }
  .btn-primary:hover { transform: translateY(-2px); box-shadow: 0 8px 28px rgba(224,48,48,0.45); }
  .btn-secondary:hover { border-color: var(--brand) !important; color: var(--brand) !important; }

  .pulse-ring { animation: pulseRing 3s ease-in-out infinite; }
  @keyframes pulseRing {
    0%,100% { opacity:.6; transform:scale(1); }
    50% { opacity:.3; transform:scale(1.06); }
  }

  /* ── Anatomy SVG animations ── */
  @keyframes bodyGlow {
    0%,100% { filter: drop-shadow(0 0 8px rgba(224,48,48,0.6)) drop-shadow(0 0 20px rgba(224,48,48,0.3)); }
    50%      { filter: drop-shadow(0 0 16px rgba(224,48,48,0.9)) drop-shadow(0 0 40px rgba(224,48,48,0.5)); }
  }
  @keyframes scanLine {
    0%   { transform: translateY(-100%); opacity: 0; }
    10%  { opacity: 1; }
    90%  { opacity: 1; }
    100% { transform: translateY(100%); opacity: 0; }
  }
  @keyframes orbPulse {
    0%,100% { r: 3; opacity: 0.7; }
    50%      { r: 5; opacity: 1; }
  }
  @keyframes dashFlow {
    to { stroke-dashoffset: -30; }
  }
  @keyframes skeletonFade {
    0%,100% { opacity: 0.5; }
    50%      { opacity: 1; }
  }
  @keyframes floatCard {
    0%,100% { transform: translateY(0px); }
    50%      { transform: translateY(-6px); }
  }
  .float-card { animation: floatCard 4s ease-in-out infinite; }
  .float-card-delay { animation: floatCard 4s ease-in-out infinite 2s; }

  .body-glow { animation: bodyGlow 3s ease-in-out infinite; }
  .scan-line { animation: scanLine 4s linear infinite; }
  .orb { animation: orbPulse 2s ease-in-out infinite; }
  .orb-d1 { animation-delay: 0.4s; }
  .orb-d2 { animation-delay: 0.8s; }
  .orb-d3 { animation-delay: 1.2s; }
  .orb-d4 { animation-delay: 1.6s; }
  .dash-flow { animation: dashFlow 1.5s linear infinite; stroke-dasharray: 8 4; }
  .skel-fade { animation: skeletonFade 2.5s ease-in-out infinite; }
  .skel-fade-d { animation: skeletonFade 2.5s ease-in-out infinite 1.25s; }

  .text-brand { color: var(--brand); }
  .bg-brand   { background-color: var(--brand); }
  .hover\\:bg-brand-dark:hover { background-color: var(--brand-dark); }
  .bg-brand\\/10 { background-color: rgba(224,48,48,0.1); }
`;

/* ── Animated Human Anatomy SVG ── */
const AnatomyModel = () => (
  <div
    className="relative w-full h-full flex items-center justify-center"
    style={{ background: 'radial-gradient(ellipse 60% 70% at 50% 50%, rgba(224,48,48,0.12) 0%, transparent 70%)' }}
  >
    {/* Rotating ring */}
    <div
      className="absolute inset-0 rounded-full"
      style={{
        border: '1px solid rgba(224,48,48,0.2)',
        animation: 'pulseRing 4s linear infinite',
        borderStyle: 'dashed',
      }}
    />

    <svg
      viewBox="0 0 200 340"
      className="w-44 h-64 body-glow"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      <defs>
        {/* Scan line clip */}
        <clipPath id="bodyClip">
          <path d="M80 10 C60 10 48 28 48 48 C48 68 58 78 68 84 L60 100 C40 104 28 110 24 130 L18 180 L30 182 L32 160 L36 200 L28 280 L44 280 L50 220 L60 280 L76 280 L72 200 L76 180 L100 176 L124 180 L128 200 L124 280 L140 280 L150 220 L156 280 L172 280 L164 200 L168 160 L170 182 L182 180 L176 130 C172 110 160 104 140 100 L132 84 C142 78 152 68 152 48 C152 28 140 10 120 10 Z" />
        </clipPath>
        <linearGradient id="bodyGrad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor="rgba(224,48,48,0.9)" />
          <stop offset="50%" stopColor="rgba(220,80,80,0.8)" />
          <stop offset="100%" stopColor="rgba(180,30,30,0.9)" />
        </linearGradient>
        <linearGradient id="innerGrad" x1="0" y1="0" x2="1" y2="1">
          <stop offset="0%" stopColor="rgba(255,160,160,0.5)" />
          <stop offset="100%" stopColor="rgba(224,48,48,0.2)" />
        </linearGradient>
      </defs>

      {/* ── Body silhouette fill ── */}
      <path
        d="M80 10 C60 10 48 28 48 48 C48 68 58 78 68 84 L60 100 C40 104 28 110 24 130 L18 180 L30 182 L32 160 L36 200 L28 280 L44 280 L50 220 L60 280 L76 280 L72 200 L76 180 L100 176 L124 180 L128 200 L124 280 L140 280 L150 220 L156 280 L172 280 L164 200 L168 160 L170 182 L182 180 L176 130 C172 110 160 104 140 100 L132 84 C142 78 152 68 152 48 C152 28 140 10 120 10 Z"
        fill="rgba(224,48,48,0.08)"
        stroke="url(#bodyGrad)"
        strokeWidth="1.5"
      />

      {/* ── Skeleton structure ── */}
      {/* Spine */}
      <line x1="100" y1="85" x2="100" y2="185" stroke="rgba(255,120,120,0.8)" strokeWidth="2" className="skel-fade" />
      {/* Ribcage */}
      <ellipse cx="100" cy="120" rx="26" ry="30" stroke="rgba(255,150,150,0.7)" strokeWidth="1.2" fill="none" className="skel-fade" />
      <ellipse cx="100" cy="120" rx="18" ry="22" stroke="rgba(255,180,180,0.5)" strokeWidth="1" fill="none" className="skel-fade-d" />
      {/* Ribs */}
      {[108, 118, 128, 138].map((y, i) => (
        <g key={y}>
          <path d={`M100 ${y} C85 ${y+4} 76 ${y+8} 74 ${y+12}`} stroke="rgba(255,140,140,0.6)" strokeWidth="1" fill="none" className={i%2===0 ? "skel-fade" : "skel-fade-d"} />
          <path d={`M100 ${y} C115 ${y+4} 124 ${y+8} 126 ${y+12}`} stroke="rgba(255,140,140,0.6)" strokeWidth="1" fill="none" className={i%2===0 ? "skel-fade" : "skel-fade-d"} />
        </g>
      ))}
      {/* Pelvis */}
      <path d="M76 180 C76 195 88 200 100 200 C112 200 124 195 124 180" stroke="rgba(255,120,120,0.7)" strokeWidth="1.5" fill="none" className="skel-fade" />
      {/* Clavicles */}
      <path d="M100 88 L72 100" stroke="rgba(255,160,160,0.8)" strokeWidth="1.5" strokeLinecap="round" className="skel-fade" />
      <path d="M100 88 L128 100" stroke="rgba(255,160,160,0.8)" strokeWidth="1.5" strokeLinecap="round" className="skel-fade" />
      {/* Skull outline */}
      <circle cx="100" cy="45" r="24" stroke="rgba(255,140,140,0.7)" strokeWidth="1.2" fill="rgba(224,48,48,0.05)" className="skel-fade" />
      {/* Eye sockets */}
      <ellipse cx="92" cy="42" rx="5" ry="4" stroke="rgba(255,120,120,0.6)" strokeWidth="1" fill="none" className="skel-fade-d" />
      <ellipse cx="108" cy="42" rx="5" ry="4" stroke="rgba(255,120,120,0.6)" strokeWidth="1" fill="none" className="skel-fade-d" />
      {/* Jaw */}
      <path d="M82 52 C88 62 112 62 118 52" stroke="rgba(255,140,140,0.6)" strokeWidth="1" fill="none" className="skel-fade" />

      {/* ── Organ hints ── */}
      {/* Heart */}
      <path d="M94 112 C94 108 88 105 86 109 C84 113 86 118 94 124 C102 118 104 113 102 109 C100 105 94 108 94 112Z"
        fill="rgba(255,60,60,0.4)" stroke="rgba(255,80,80,0.8)" strokeWidth="1" className="orb" />
      {/* Lungs */}
      <ellipse cx="84" cy="120" rx="9" ry="14" fill="rgba(224,100,100,0.15)" stroke="rgba(255,140,140,0.5)" strokeWidth="1" className="skel-fade-d" />
      <ellipse cx="116" cy="120" rx="9" ry="14" fill="rgba(224,100,100,0.15)" stroke="rgba(255,140,140,0.5)" strokeWidth="1" className="skel-fade-d" />

      {/* ── Data flow lines (dashed animated) ── */}
      <line x1="100" y1="88" x2="100" y2="180" stroke="rgba(255,100,100,0.4)" strokeWidth="1" className="dash-flow" />
      <line x1="74" y1="100" x2="24" y2="140" stroke="rgba(255,100,100,0.3)" strokeWidth="1" className="dash-flow" />
      <line x1="126" y1="100" x2="176" y2="140" stroke="rgba(255,100,100,0.3)" strokeWidth="1" className="dash-flow" />

      {/* ── Hotspot orbs ── */}
      <circle cx="100" cy="48" r="3" fill="rgba(255,80,80,0.9)" className="orb orb-d1" />
      <circle cx="94" cy="112" r="4" fill="rgba(255,50,50,0.95)" className="orb orb-d2" />
      <circle cx="100" cy="155" r="3" fill="rgba(255,80,80,0.9)" className="orb orb-d3" />
      <circle cx="78" cy="240" r="3" fill="rgba(255,100,100,0.8)" className="orb orb-d4" />
      <circle cx="122" cy="240" r="3" fill="rgba(255,100,100,0.8)" className="orb orb-d1" />

      {/* ── Scan line effect ── */}
      <g clipPath="url(#bodyClip)">
        <rect
          x="18" y="0" width="164" height="8"
          fill="url(#innerGrad)"
          opacity="0.6"
          className="scan-line"
        />
      </g>
    </svg>

    {/* Outer glow ring */}
    <div
      className="absolute inset-0 rounded-full pointer-events-none"
      style={{
        background: 'radial-gradient(circle, rgba(224,48,48,0.08) 0%, transparent 70%)',
        animation: 'pulseRing 2.5s ease-in-out infinite',
      }}
    />
  </div>
);

/* ── Stars ── */
const Stars = ({ count = 5 }) => (
  <div className="flex gap-0.5">
    {Array.from({ length: count }).map((_, i) => (
      <svg key={i} className="w-4 h-4 text-amber-400" fill="currentColor" viewBox="0 0 20 20">
        <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
      </svg>
    ))}
  </div>
);

/* ── Hero ── */
const Hero = () => {
  const scrollTo = (id) => document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });

  const stats = [
    ['10000+', 'Patients Treated'],
    ['15+', 'Years Experience'],
    ['98%',   'Success Rate'],
  ];

  return (
    <>
      <style>{STYLE}</style>
      <section
        id="home"
        className="hero-gradient mesh-bg min-h-screen flex items-center pt-20 relative overflow-hidden"
      >
        {/* Background blobs */}
        <div className="absolute inset-0 overflow-hidden pointer-events-none">
          <div className="absolute -top-20 -right-20 w-96 h-96 bg-red-200/30 rounded-full blur-3xl pulse-ring" />
          <div className="absolute bottom-0 left-0 w-72 h-72 bg-cyan-200/20 rounded-full blur-3xl" />
          <div className="absolute top-1/2 left-1/3 w-48 h-48 bg-red-100/40 rounded-full blur-2xl" />
        </div>

        <div className="max-w-6xl mx-auto px-6 py-24 grid lg:grid-cols-2 gap-16 items-center relative">

          {/* ── Left Content ── */}
          <div>
            <div className="inline-flex items-center gap-2 bg-red-50 border border-red-100 rounded-full px-4 py-2 mb-8">
              <div className="w-2 h-2 bg-red-400 rounded-full" style={{ animation: 'pulse 2s infinite' }} />
              <span className="text-brand text-xs font-semibold tracking-widest uppercase">
                Accepting New Patients
              </span>
            </div>

            <h1 className="text-5xl lg:text-6xl font-bold text-slate-800 leading-tight mb-6"
              style={{ fontFamily: "'Playfair Display', serif" }}>
              Restore Your<br />
              <span className="text-brand">Movement,</span><br />
              Reclaim Your Life
            </h1>

            <p className="text-lg text-slate-500 leading-relaxed mb-10 max-w-md font-light"
              style={{ fontFamily: "'DM Sans', sans-serif" }}>
              Expert physiotherapy and rehabilitation care tailored to your unique recovery journey.
              Evidence-based treatments, compassionate professionals.
            </p>

            <div className="flex flex-col sm:flex-row gap-4">
              <button
                onClick={() => scrollTo('contact')}
                className="btn-primary bg-brand text-white font-semibold px-8 py-4 rounded-2xl text-base border-none cursor-pointer"
                style={{ fontFamily: "'DM Sans', sans-serif" }}
              >
                Schedule a Consultation →
              </button>
              <button
                onClick={() => scrollTo('services')}
                className="btn-secondary border-2 border-slate-200 text-slate-600 font-semibold px-8 py-4 rounded-2xl text-base cursor-pointer bg-transparent"
                style={{ fontFamily: "'DM Sans', sans-serif", transition: 'border-color 0.2s, color 0.2s' }}
              >
                Our Services
              </button>
            </div>

            {/* Stats */}
            <div className="flex items-center gap-8 mt-12 pt-8 border-t border-slate-200/60">
              {stats.map(([num, label]) => (
                <div key={label}>
                  <div className="text-2xl font-bold text-slate-800"
                    style={{ fontFamily: "'Playfair Display', serif" }}>
                    {num}
                  </div>
                  <div className="text-xs text-slate-400 font-medium mt-0.5"
                    style={{ fontFamily: "'DM Sans', sans-serif" }}>
                    {label}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* ── Right: Anatomy Illustration ── */}
          <div className="hidden lg:flex justify-center items-center relative">
            <div className="relative w-80 h-96">

              {/* Outer pulse ring */}
              <div className="absolute inset-0 bg-brand/10 rounded-full pulse-ring" />

              {/* Main anatomy card */}
              <div
                className="absolute inset-4 rounded-3xl flex items-center justify-center shadow-2xl overflow-hidden"
                style={{
                  background: 'linear-gradient(135deg, #1a0505 0%, #2d0a0a 40%, #1a0505 100%)',
                  border: '1px solid rgba(224,48,48,0.3)',
                  boxShadow: '0 0 40px rgba(224,48,48,0.2), inset 0 1px 0 rgba(255,255,255,0.05)',
                }}
              >
                {/* Grid overlay */}
                <div
                  className="absolute inset-0 pointer-events-none opacity-10"
                  style={{
                    backgroundImage: 'linear-gradient(rgba(224,48,48,0.5) 1px, transparent 1px), linear-gradient(90deg, rgba(224,48,48,0.5) 1px, transparent 1px)',
